import {type KeyboardEventHandler, useEffect, useState} from "react";
import {Slider} from "primereact/slider";
import {InputNumber, type InputNumberChangeEvent} from "primereact/inputnumber";
import {isEqual} from "lodash";
import {type EditorEl} from "../Editor";
import type {Timeout} from "@lmb-it/kitsconcerto-types";

const timeoutPeriod = 500;

const NumberFilterElement: EditorEl<{ min: number; max: number }> = ({
  max,
  min,
  ...options
}) => {
  const [value, setValue] = useState<number | null>(null);
  const [timeoutId, setTimeoutId] = useState<Timeout | null>(null);

  useEffect(() => {
    if (options && "value" in options) {
      if (typeof options.value == "number") {
        setValue(options.value);
      } else {
        setValue(null);
      }
    }
  }, [options]);

  const onInputChange = (event: InputNumberChangeEvent) => {
    const newTerm = event.value;
    setValue(newTerm);

    if (timeoutId) clearTimeout(timeoutId);

    const newTimeoutId = setTimeout(() => {
      options.editorCallback && options.editorCallback(newTerm);
    }, timeoutPeriod);

    setTimeoutId(newTimeoutId);
  };

  const onKeyDown: KeyboardEventHandler<HTMLInputElement> = (event) => {
    if (event.key === "Enter") {
      if (timeoutId) clearTimeout(timeoutId);
      options.editorCallback && options.editorCallback(value);
    }
  };

  return (
    <InputNumber
      id={"filter-number"}
      value={value}
      style={{ width: "100%" }}
      min={min}
      max={max}
      onChange={onInputChange}
      onKeyDown={onKeyDown}
    />
  );
};

const RangeFilterElement: EditorEl<{ min: number; max: number }> = ({
  min,
  max,
  ...options
}) => {
  const [value, setValue] = useState<[number, number]>([min, max]);

  useEffect(() => {
    if (options && "value" in options) {
      if (
        Array.isArray(options.value) &&
        options.value.length == 2
      ) {
        const v = options.value;
        if (typeof v[0] == "number" && typeof v[1] === "number") {
          setValue([v[0], v[1]]);
        }
      } else {
        if (!options["value"] && !isEqual(value, [min, max])) {
          setValue([min, max]);
        }
      }
    }
  }, [options]);

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "row",
        gap: 2,
        width: "100%",
        justifyContent: "space-between",
        alignItems: "center",
      }}
    >
      <span>{value ? value[0] : min}</span>
      <Slider
        value={value}
        style={{ width: "90%", margin: "0 13px" }}
        onChange={(e) => {
          const v = e.value;

          Array.isArray(v) &&
            setValue(
              v.sort(function (a, b) {
                return a - b;
              }),
            );
        }}
        onSlideEnd={(event) => {
          Array.isArray(event.value) &&
          options.editorCallback && options.editorCallback(
              event.value.sort(function (a, b) {
                return a - b;
              }),
            );
        }}
        prefix={"%"}
        range
        min={min}
        max={max}
      />
      <span>{value ? value[1] : max}</span>
    </div>
  );
};

const SliderFilterElement: EditorEl<{ min: number; max: number }> = (
  options,
) => {
  const isRange = false;

  if (isRange) {
    return <RangeFilterElement {...options} />;
  } else {
    if (typeof NumberFilterElement == "function") {
      return <NumberFilterElement {...options} />;
    } else {
      return <div />;
    }
  }
};

export default SliderFilterElement;
